import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { 
  FileText, 
  Clock, 
  CheckCircle, 
  AlertCircle,
  TrendingUp,
  Calendar,
  MapPin
} from 'lucide-react';

const WorkerDashboard = () => {
  const { user, api } = useAuth();
  const [stats, setStats] = useState({
    assigned: 0,
    inProgress: 0,
    completed: 0,
    pending: 0,
  });
  const [assignedComplaints, setAssignedComplaints] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);

      // Fetch worker's complaints
      const complaintsResponse = await api.get('/complaints?size=10&sortBy=createdAt&sortDir=desc');
      const complaints = complaintsResponse.data.content || complaintsResponse.data;

      // Filter for assigned complaints and calculate stats
      const assigned = complaints.filter(complaint => 
        complaint.assignedWorker?.id === user?.id || complaint.status === 'PENDING'
      );

      const stats = assigned.reduce((acc, complaint) => {
        if (complaint.assignedWorker?.id === user?.id) {
          acc.assigned++;
          switch (complaint.status) {
            case 'PENDING':
              acc.pending++;
              break;
            case 'IN_PROGRESS':
              acc.inProgress++;
              break;
            case 'RESOLVED':
              acc.completed++;
              break;
          }
        }
        return acc;
      }, { assigned: 0, inProgress: 0, completed: 0, pending: 0 });

      setStats(stats);
      setAssignedComplaints(assigned.slice(0, 5)); // Show only first 5
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'PENDING':
        return <Clock className="h-4 w-4 text-warning-600" />;
      case 'IN_PROGRESS':
        return <AlertCircle className="h-4 w-4 text-primary-600" />;
      case 'RESOLVED':
        return <CheckCircle className="h-4 w-4 text-success-600" />;
      default:
        return <Clock className="h-4 w-4 text-gray-600" />;
    }
  };

  const getStatusClass = (status) => {
    switch (status) {
      case 'PENDING':
        return 'status-pending';
      case 'IN_PROGRESS':
        return 'status-in-progress';
      case 'RESOLVED':
        return 'status-resolved';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getPriorityClass = (priority) => {
    switch (priority) {
      case 'LOW':
        return 'priority-low';
      case 'MEDIUM':
        return 'priority-medium';
      case 'HIGH':
        return 'priority-high';
      case 'URGENT':
        return 'priority-urgent';
      default:
        return 'priority-medium';
    }
  };

  const updateComplaintStatus = async (complaintId, newStatus) => {
    try {
      await api.put(`/complaints/${complaintId}/status`, { status: newStatus });
      fetchDashboardData(); // Refresh data
    } catch (error) {
      console.error('Error updating complaint status:', error);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Welcome Section */}
      <div className="bg-gradient-to-r from-primary-600 to-primary-700 rounded-xl p-6 text-white">
        <h1 className="text-2xl font-bold mb-2">
          Worker Dashboard
        </h1>
        <p className="text-primary-100">
          Manage and resolve assigned infrastructure complaints
        </p>
      </div>

      {/* Statistics */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="card">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Assigned Tasks</p>
              <p className="text-2xl font-bold text-gray-900">{stats.assigned}</p>
            </div>
            <div className="p-3 bg-blue-100 rounded-lg">
              <FileText className="h-6 w-6 text-blue-600" />
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">In Progress</p>
              <p className="text-2xl font-bold text-primary-600">{stats.inProgress}</p>
            </div>
            <div className="p-3 bg-primary-100 rounded-lg">
              <AlertCircle className="h-6 w-6 text-primary-600" />
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Completed</p>
              <p className="text-2xl font-bold text-success-600">{stats.completed}</p>
            </div>
            <div className="p-3 bg-success-100 rounded-lg">
              <CheckCircle className="h-6 w-6 text-success-600" />
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Pending</p>
              <p className="text-2xl font-bold text-warning-600">{stats.pending}</p>
            </div>
            <div className="p-3 bg-warning-100 rounded-lg">
              <Clock className="h-6 w-6 text-warning-600" />
            </div>
          </div>
        </div>
      </div>

      {/* Assigned Complaints */}
      <div className="card">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-semibold text-gray-900">Your Assigned Complaints</h2>
          <Link
            to="/complaints"
            className="text-sm text-primary-600 hover:text-primary-500 font-medium"
          >
            View All
          </Link>
        </div>

        {assignedComplaints.length === 0 ? (
          <div className="text-center py-8">
            <FileText className="h-12 w-12 text-gray-400 mx-auto mb-4" />
            <p className="text-gray-500">No complaints assigned to you yet</p>
            <p className="text-sm text-gray-400 mt-2">
              New complaints will appear here when assigned by an admin
            </p>
          </div>
        ) : (
          <div className="space-y-4">
            {assignedComplaints.map((complaint) => (
              <div
                key={complaint.id}
                className="border border-gray-200 rounded-lg p-4 hover:bg-gray-50 transition-colors"
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <div className="flex items-center space-x-2 mb-2">
                      <h3 className="text-sm font-medium text-gray-900">{complaint.title}</h3>
                      <span className={`status-badge ${getStatusClass(complaint.status)}`}>
                        {complaint.status.toLowerCase().replace('_', ' ')}
                      </span>
                      <span className={`status-badge ${getPriorityClass(complaint.priority)}`}>
                        {complaint.priority.toLowerCase()}
                      </span>
                    </div>
                    <p className="text-sm text-gray-600 line-clamp-2">{complaint.description}</p>
                    <div className="flex items-center space-x-4 mt-2 text-xs text-gray-500">
                      <div className="flex items-center space-x-1">
                        <Calendar className="h-3 w-3" />
                        <span>{new Date(complaint.createdAt).toLocaleDateString()}</span>
                      </div>
                      <div className="flex items-center space-x-1">
                        <span>By: {complaint.user?.name}</span>
                      </div>
                      {complaint.blockNumber && (
                        <div className="flex items-center space-x-1">
                          <MapPin className="h-3 w-3" />
                          <span>Block: {complaint.blockNumber}</span>
                        </div>
                      )}
                      {complaint.roomNumber && (
                        <span>Room: {complaint.roomNumber}</span>
                      )}
                    </div>
                  </div>
                  <div className="flex items-center space-x-2 ml-4">
                    {getStatusIcon(complaint.status)}
                    <div className="flex flex-col space-y-1">
                      <Link
                        to={`/complaints/${complaint.id}`}
                        className="text-primary-600 hover:text-primary-500 text-sm font-medium"
                      >
                        View Details
                      </Link>
                      {complaint.status === 'PENDING' && (
                        <button
                          onClick={() => updateComplaintStatus(complaint.id, 'IN_PROGRESS')}
                          className="text-xs bg-primary-100 text-primary-700 px-2 py-1 rounded hover:bg-primary-200"
                        >
                          Start Work
                        </button>
                      )}
                      {complaint.status === 'IN_PROGRESS' && (
                        <button
                          onClick={() => updateComplaintStatus(complaint.id, 'RESOLVED')}
                          className="text-xs bg-success-100 text-success-700 px-2 py-1 rounded hover:bg-success-200"
                        >
                          Mark Complete
                        </button>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <Link
          to="/complaints"
          className="card hover:shadow-lg transition-shadow duration-200 group"
        >
          <div className="flex items-center space-x-4">
            <div className="flex-shrink-0">
              <div className="p-3 bg-secondary-100 rounded-lg group-hover:bg-secondary-200 transition-colors">
                <FileText className="h-6 w-6 text-secondary-600" />
              </div>
            </div>
            <div>
              <p className="text-sm font-medium text-gray-900">View All Complaints</p>
              <p className="text-xs text-gray-500">Browse all available complaints</p>
            </div>
          </div>
        </Link>

        <div className="card">
          <div className="flex items-center space-x-4">
            <div className="flex-shrink-0">
              <div className="p-3 bg-success-100 rounded-lg">
                <TrendingUp className="h-6 w-6 text-success-600" />
              </div>
            </div>
            <div>
              <p className="text-sm font-medium text-gray-900">Performance</p>
              <p className="text-xs text-gray-500">
                {stats.completed > 0 ? `${stats.completed} tasks completed` : 'Start working to track performance'}
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default WorkerDashboard;
